#graphql
  query OnlineStoreContentBaseline($missingArticle: ID!, $missingBlog: ID!, $missingPage: ID!) {
    article(id: $missingArticle) { id title }
    blog(id: $missingBlog) { id title }
    page(id: $missingPage) { id title }
    articles(first: 5) {
      edges {
        cursor
        node {
          id
          title
          handle
          body
          summary
          tags
          isPublished
          publishedAt
          createdAt
          updatedAt
          templateSuffix
          blog { id title handle }
          author { name }
          commentsCount { count precision }
          comments(first: 5) {
            nodes { id body status }
            pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
          }
        }
      }
      nodes { id title handle }
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
    }
    articleAuthors(first: 5) {
      edges { cursor node { name } }
      nodes { name }
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
    }
    articleTags(limit: 20)
    blogs(first: 5) {
      edges {
        cursor
        node {
          id
          title
          handle
          commentPolicy
          tags
          templateSuffix
          createdAt
          updatedAt
          articlesCount { count precision }
          articles(first: 5) {
            nodes { id title handle }
            pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
          }
        }
      }
      nodes { id title handle }
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
    }
    blogsCount { count precision }
    pages(first: 5) {
      edges {
        cursor
        node {
          id
          title
          handle
          body
          bodySummary
          isPublished
          publishedAt
          createdAt
          updatedAt
          templateSuffix
        }
      }
      nodes { id title handle }
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
    }
    pagesCount { count precision }
    comments(first: 5) {
      edges {
        cursor
        node {
          id
          body
          bodyHtml
          status
          isPublished
          publishedAt
          createdAt
          updatedAt
          ip
          userAgent
          article { id title }
          author { name }
        }
      }
      nodes { id body status }
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
    }
  }

mutation OnlineStoreContentCreate($blog: BlogCreateInput!, $page: PageCreateInput!) {
  blogCreate(blog: $blog) {
    blog {
      id
      title
      handle
      commentPolicy
      templateSuffix
      tags
      articlesCount {
        count
        precision
      }
    }
    userErrors {
      field
      message
    }
  }
  pageCreate(page: $page) {
    page {
      id
      title
      handle
      body
      bodySummary
      isPublished
      templateSuffix
    }
    userErrors {
      field
      message
    }
  }
}

mutation OnlineStoreContentArticleCreate($article: ArticleCreateInput!) {
  articleCreate(article: $article) {
    article {
      id
      title
      handle
      body
      summary
      tags
      isPublished
      templateSuffix
      author {
        name
      }
      blog {
        id
        title
        handle
      }
      commentsCount {
        count
        precision
      }
    }
    userErrors {
      field
      message
    }
  }
}

mutation OnlineStoreContentUpdate(
  $blogId: ID!
  $blog: BlogUpdateInput!
  $pageId: ID!
  $page: PageUpdateInput!
  $articleId: ID!
  $article: ArticleUpdateInput!
) {
  blogUpdate(id: $blogId, blog: $blog) {
    blog {
      id
      title
      handle
      commentPolicy
    }
    userErrors {
      field
      message
    }
  }
  pageUpdate(id: $pageId, page: $page) {
    page {
      id
      title
      handle
      body
      bodySummary
      isPublished
      publishedAt
    }
    userErrors {
      field
      message
    }
  }
  articleUpdate(id: $articleId, article: $article) {
    article {
      id
      title
      handle
      body
      summary
      tags
      isPublished
      publishedAt
      author {
        name
      }
    }
    userErrors {
      field
      message
    }
  }
}

query OnlineStoreContentReadAfterUpdate($blogId: ID!, $pageId: ID!, $articleId: ID!, $articleQuery: String!) {
  blog(id: $blogId) {
    id
    title
    articlesCount {
      count
      precision
    }
    articles(first: 5) {
      nodes {
        id
        title
        handle
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }
  page(id: $pageId) {
    id
    title
    isPublished
  }
  article(id: $articleId) {
    id
    title
    isPublished
    blog {
      id
      title
    }
  }
  articles(first: 5, query: $articleQuery) {
    nodes {
      id
      title
      tags
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
  articleAuthors(first: 10) {
    nodes {
      name
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
  articleTags(limit: 20)
  blogsCount {
    count
    precision
  }
  pagesCount {
    count
    precision
  }
}

mutation OnlineStoreContentCommentUnknown($id: ID!) {
  commentApprove(id: $id) {
    comment {
      id
      status
    }
    userErrors {
      field
      message
    }
  }
  commentSpam(id: $id) {
    comment {
      id
      status
    }
    userErrors {
      field
      message
    }
  }
  commentNotSpam(id: $id) {
    comment {
      id
      status
    }
    userErrors {
      field
      message
    }
  }
  commentDelete(id: $id) {
    deletedCommentId
    userErrors {
      field
      message
    }
  }
}

mutation OnlineStoreContentDelete($articleId: ID!, $pageId: ID!, $blogId: ID!) {
  articleDelete(id: $articleId) {
    deletedArticleId
    userErrors {
      field
      message
    }
  }
  pageDelete(id: $pageId) {
    deletedPageId
    userErrors {
      field
      message
    }
  }
  blogDelete(id: $blogId) {
    deletedBlogId
    userErrors {
      field
      message
    }
  }
}
